solution: class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        bool hasOneS = false;
        bool hasOneTarget = false;
        for (char c : s) if (c == '1') { hasOneS = true; break; }
        for (char c : target) if (c == '1') { hasOneTarget = true; break; }
        return hasOneS == hasOneTarget;
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
